import { Component, Input, OnDestroy, OnInit, HostListener } from '@angular/core';
import { interval, Subscription, fromEvent } from 'rxjs';

@Component({
  selector: 'app-carousel',
  templateUrl: './carousel.component.html',
  styleUrls: ['./carousel.component.scss'],
})
export class CarouselComponent implements OnInit, OnDestroy {
  /** Image URLs – can be passed in by the parent */
  @Input() images: string[] = [
    // Default placeholder images
    'https://picsum.photos/id/1015/800/500',
    'https://picsum.photos/id/1020/800/500',
    'https://picsum.photos/id/1024/800/500',
    'https://picsum.photos/id/1033/800/500',
    'https://picsum.photos/id/1049/800/500',
  ];

  /** How many slides are visible at once */
  slidesToShow = 1;
  /** Current start index (0‑based) of the viewport */
  currentIndex = 0;

  /* ---- private helpers ------------------------------------------------- */

  private autoPlay$?: Subscription;          // Auto‑slide timer
  private resize$?: Subscription;            // Window resize listener
  private dragStartX = 0;                    // X position when dragging starts

  /** Width of a single slide in % (e.g. 33.333% for 3 slides) */
  get slideWidthPercent(): number {
    return 100 / this.slidesToShow;
  }

  /** CSS transform applied to the slides container */
  get translateX(): string {
    const pct = -this.currentIndex * this.slideWidthPercent;
    return `translateX(${pct}%)`;
  }

  /* ---- life‑cycle ----------------------------------------------------- */

  ngOnInit() {
    this.updateSlidesToShow();   // initial calculation
    this.startAutoPlay();
    this.resize$ = fromEvent(window, 'resize').subscribe(() => this.updateSlidesToShow());
  }

  ngOnDestroy() {
    this.autoPlay$?.unsubscribe();
    this.resize$?.unsubscribe();
  }

  /* ---- auto‑play ------------------------------------------------------- */

  private startAutoPlay() {
    // change slide every 3 s
    this.autoPlay$ = interval(3000).subscribe(() => this.next());
  }

  /* ---- navigation helpers ---------------------------------------------- */

  next(): void {
    if (this.currentIndex < this.images.length - 1) {
      this.currentIndex++;
    } else {
      this.currentIndex = 0;   // wrap back to start
    }
  }

  prev(): void {
    if (this.currentIndex > 0) {
      this.currentIndex--;
    } else {
      this.currentIndex = this.images.length - 1;
    }
  }

  /* ---- responsive logic ------------------------------------------------ */

  private updateSlidesToShow() {
    const width = window.innerWidth;

    // you can fine‑tune these breakpoints as needed
    if (width >= 1024) {
      this.slidesToShow = Math.min(3, this.images.length);
    } else if (width >= 640) {
      this.slidesToShow = Math.min(2, this.images.length);
    } else {
      this.slidesToShow = 1;
    }
  }

  /* ---- drag / swipe support -------------------------------------------- */

  @HostListener('pointerdown', ['$event'])
  onPointerDown(e: PointerEvent) {
    e.preventDefault();        // avoid text selection
    this.dragStartX = e.clientX;
  }

  @HostListener('pointerup', ['$event'])
  onPointerUp(e: PointerEvent) {
    const delta = e.clientX - this.dragStartX;
    const threshold = 50;      // px

    if (delta > threshold) {
      this.prev();            // dragged right → previous slide
    } else if (delta < -threshold) {
      this.next();            // dragged left → next slide
    }
  }

  @HostListener('pointerleave', ['$event'])
  onPointerLeave(e: PointerEvent) {
    // cancel drag if the pointer leaves the carousel area mid‑drag
    this.dragStartX = 0;
  }
}
